import type { ComponentProps, ComponentRef } from 'react';
import { Fieldset as FieldsetPrimitive, useFieldset } from '@ark-ui/react/fieldset';
import { clsx } from 'clsx';
import { forwardRef } from 'react';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import styles from './Fieldset.module.css';

const FieldsetRoot = forwardRef<
  ComponentRef<typeof FieldsetPrimitive.Root>,
  ComponentProps<typeof FieldsetPrimitive.Root>
>(function FieldsetRoot({ className, ...props }, ref) {
  return (
    <FieldsetPrimitive.Root
      ref={ref}
      data-slot="fieldset-root"
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const FieldsetRootProvider = forwardRef<
  ComponentRef<typeof FieldsetPrimitive.RootProvider>,
  ComponentProps<typeof FieldsetPrimitive.RootProvider>
>(function FieldsetRootProvider({ className, ...props }, ref) {
  return (
    <FieldsetPrimitive.RootProvider
      ref={ref}
      data-slot="fieldset-root-provider"
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const FieldsetLegend = forwardRef<
  ComponentRef<typeof FieldsetPrimitive.Legend>,
  ComponentProps<typeof FieldsetPrimitive.Legend>
>(function FieldsetLegend({ className, ...props }, ref) {
  return (
    <FieldsetPrimitive.Legend
      ref={ref}
      data-slot="fieldset-legend"
      className={clsx(styles.legend, normalizeClassName(className))}
      {...props}
    />
  );
});

const FieldsetHelperText = forwardRef<
  ComponentRef<typeof FieldsetPrimitive.HelperText>,
  ComponentProps<typeof FieldsetPrimitive.HelperText>
>(function FieldsetHelperText({ className, ...props }, ref) {
  return (
    <FieldsetPrimitive.HelperText
      ref={ref}
      data-slot="fieldset-helper-text"
      className={clsx(styles.helperText, normalizeClassName(className))}
      {...props}
    />
  );
});

const FieldsetErrorText = forwardRef<
  ComponentRef<typeof FieldsetPrimitive.ErrorText>,
  ComponentProps<typeof FieldsetPrimitive.ErrorText>
>(function FieldsetErrorText({ className, ...props }, ref) {
  return (
    <FieldsetPrimitive.ErrorText
      ref={ref}
      data-slot="fieldset-error-text"
      className={clsx(styles.errorText, normalizeClassName(className))}
      {...props}
    />
  );
});

const Fieldset = Object.assign(FieldsetRoot, {
  Root: FieldsetRoot,
  RootProvider: FieldsetRootProvider,
  Legend: FieldsetLegend,
  HelperText: FieldsetHelperText,
  ErrorText: FieldsetErrorText,
});

export { Fieldset, useFieldset };

@layer ui.components {
  .root,
  .legend,
  .helperText,
  .errorText {
    box-sizing: border-box;
  }

  .root {
    display: flex;
    flex-direction: column;
    gap: var(--fieldset-gap, var(--spacing-4));
    width: var(--fieldset-width, 100%);
    max-width: var(--fieldset-max-width, none);
    margin: var(--fieldset-margin, 0);
    padding: var(--fieldset-padding, 0);
    border-width: var(--fieldset-border-width, 0);
    border-style: var(--fieldset-border-style, solid);
    border-color: var(--fieldset-border-color, transparent);
    border-radius: var(--fieldset-radius, var(--radius-none));
    min-inline-size: 0;

    &[data-disabled] {
      opacity: var(--fieldset-disabled-opacity, var(--opacity-disabled));
    }

    &[data-invalid] {
      border-color: var(--fieldset-border-color-invalid, var(--color-destructive));
    }
  }

  .legend {
    display: inline-block;
    max-inline-size: 100%;
    margin: var(--fieldset-legend-margin, 0);
    padding: var(--fieldset-legend-padding, 0 0 var(--spacing-3));
    color: var(--fieldset-legend-color, var(--color-foreground));
    font-size: var(--fieldset-legend-font-size, var(--text-lg));
    font-weight: var(--fieldset-legend-font-weight, var(--weight-semibold));
    line-height: var(--fieldset-legend-line-height, var(--line-height-text-lg));
  }

  .helperText,
  .errorText {
    font-size: var(--fieldset-message-font-size, var(--text-sm));
    line-height: var(--fieldset-message-line-height, var(--line-height-text-sm));
  }

  .helperText {
    color: var(--fieldset-helper-text-color, var(--color-muted-foreground));
  }

  .errorText {
    color: var(--fieldset-error-text-color, var(--color-destructive));
  }
}
